import type {
  FilterFieldNode,
  FilterFieldStatementNode,
  FilterFieldTree,
} from '../../types/tree-nodes.js';
import { isFilterFieldStatementNode } from '../tree-node-guards.js';

function findStatement(cursorPosition: number, node?: FilterFieldNode) {
  if (
    !node ||
    !(node.range.from <= cursorPosition && node.range.to >= cursorPosition)
  ) {
    return null;
  }

  if (node.type === 'Group') {
    if (node.children.length === 0 || node.children[0].type === 'Error') {
      // If it is an empty group it should be treated as an empty statement
      return {} as FilterFieldNode;
    }

    let newNode: FilterFieldNode | null = null;
    node.children.forEach((childNode) => {
      const temp = findStatement(cursorPosition, childNode);
      if (temp) {
        newNode = temp;
      }
    });

    return newNode;
  }

  if (node.type === 'Statement') {
    return node;
  }

  return null;
}

/**
 * Get the filter statement around the given cursor position.
 * @internal
 */
export function getFilterStatement(
  tree: FilterFieldTree,
  cursorPosition: number,
  doc?: string,
): FilterFieldStatementNode | undefined {
  if (!doc) {
    return;
  }

  let statementNode;

  if (!tree) {
    return;
  }

  for (const node of tree.children) {
    const temp = findStatement(cursorPosition, node);

    if (temp) {
      statementNode = temp;
    }
  }

  if (!statementNode || !isFilterFieldStatementNode(statementNode)) {
    return;
  }

  return statementNode;
}
